// The query executed by getReportWithFights.
const getReportWithFights_Operation = `
query getReportWithFights ($code: String!, $allowUnlisted: Boolean, $encounterID: Int, $difficulty: Int, $killType: KillType, $fightIDs: [Int], $translate: Boolean) {
	reportData {
		report(code: $code, allowUnlisted: $allowUnlisted) {
			... Report
			fights(encounterID: $encounterID, difficulty: $difficulty, killType: $killType, fightIDs: $fightIDs, translate: $translate) {
				... ReportFight
			}
			phases {
				... EncounterPhases
			}
		}
	}
}
fragment Report on Report {
	code
	title
	startTime
	endTime
	visibility
	revision
	segments
	exportedSegments
	zone {
		... ZoneSummary
	}
	guild {
		id
		name
	}
	owner {
		... User
	}
	region {
		id
		name
	}
	archiveStatus {
		isArchived
		isAccessible
		archiveDate
	}
}
fragment ReportFight on ReportFight {
	id
	name
	encounterID
	originalEncounterID
	difficulty
	size
	kill
	inProgress
	completeRaid
	startTime
	endTime
	fightPercentage
	bossPercentage
	averageItemLevel
	friendlyPlayers
	enemyPlayers
	keystoneLevel
	keystoneTime
	keystoneBonus
	keystoneAffixes
	hardModeLevel
	lastPhase
	lastPhaseAsAbsoluteIndex
	lastPhaseIsIntermission
	phaseTransitions {
		... PhaseTransition
	}
	gameZone {
		... GameZoneSummary
	}
}
fragment EncounterPhases on EncounterPhases {
	encounterID
	separatesWipes
	phases {
		... PhaseMetadata
	}
}
fragment ZoneSummary on Zone {
	id
	name
}
fragment User on User {
	id
	name
}
fragment PhaseTransition on PhaseTransition {
	id
	startTime
}
fragment GameZoneSummary on GameZone {
	id
	name
}
fragment PhaseMetadata on PhaseMetadata {
	id
	name
	isIntermission
}
`

// Header, fights and phases in a single request. The API charges the fight load
// once, so all three cost no more than fetching the fights alone.
